import pytest
from your_module import run_length_encode  # Replace with actual module name


class TestRunLengthEncodeHappyPath:
    """Tests for normal, expected use cases."""

    def test_single_character(self):
        """Test encoding a single character."""
        assert run_length_encode("a") == [("a", 1)]

    def test_all_different_characters(self):
        """Test string with all unique characters."""
        assert run_length_encode("abcd") == [("a", 1), ("b", 1), ("c", 1), ("d", 1)]

    def test_all_same_characters(self):
        """Test string with all identical characters."""
        assert run_length_encode("aaaa") == [("a", 4)]

    def test_mixed_runs(self):
        """Test string with mixed character runs."""
        assert run_length_encode("aabbcc") == [("a", 2), ("b", 2), ("c", 2)]

    def test_complex_pattern(self):
        """Test complex pattern with varying run lengths."""
        assert run_length_encode("aaabbaaa") == [("a", 3), ("b", 2), ("a", 3)]

    def test_single_run_with_others(self):
        """Test runs with single character interruptions."""
        assert run_length_encode("aaabaaaa") == [("a", 3), ("b", 1), ("a", 4)]

    def test_numeric_characters(self):
        """Test encoding numeric characters."""
        assert run_length_encode("1112223") == [("1", 3), ("2", 3), ("3", 1)]

    def test_special_characters(self):
        """Test encoding special characters."""
        assert run_length_encode("!!!@@##") == [("!", 3), ("@", 2), ("#", 2)]

    def test_whitespace_characters(self):
        """Test encoding whitespace characters."""
        assert run_length_encode("   aa  ") == [(" ", 3), ("a", 2), (" ", 2)]


class TestRunLengthEncodeEdgeCases:
    """Tests for edge cases and boundary conditions."""

    def test_empty_string(self):
        """Test with empty string."""
        assert run_length_encode("") == []

    def test_two_characters_same(self):
        """Test with two identical characters."""
        assert run_length_encode("aa") == [("a", 2)]

    def test_two_characters_different(self):
        """Test with two different characters."""
        assert run_length_encode("ab") == [("a", 1), ("b", 1)]

    def test_very_long_run(self):
        """Test with very long run of same character."""
        assert run_length_encode("a" * 1000) == [("a", 1000)]

    def test_alternating_characters(self):
        """Test with alternating characters."""
        assert run_length_encode("ababab") == [("a", 1), ("b", 1), ("a", 1), ("b", 1), ("a", 1), ("b", 1)]

    def test_unicode_characters(self):
        """Test with unicode characters."""
        assert run_length_encode("αααββγ") == [("α", 3), ("β", 2), ("γ", 1)]

    def test_mixed_case_letters(self):
        """Test that uppercase and lowercase are treated as different."""
        assert run_length_encode("AAAaaa") == [("A", 3), ("a", 3)]

    def test_newline_characters(self):
        """Test with newline characters."""
        assert run_length_encode("aa\n\nbb") == [("a", 2), ("\n", 2), ("b", 2)]
